<template><Head :title="plan.name" /><DealerLayout title="Plan Details" eyebrow="Subscription checkout"><Link :href="actions.index" class="text-sm font-black text-teal-700">Back to plans</Link><section class="mt-5 grid gap-5 lg:grid-cols-2"><div class="rounded-lg border border-slate-200 bg-white p-5 shadow-sm"><h2 class="text-3xl font-black text-slate-950">{{ plan.name }}</h2><p class="mt-3 text-4xl font-black text-teal-700">{{ plan.price===0?'Free':money(plan.price) }}</p><div class="mt-6 space-y-3 text-sm font-semibold text-slate-600"><p>{{ plan.listing_limit }} car listings</p><p>{{ plan.duration_days }} days validity</p><p v-if="plan.description">{{ plan.description }}</p></div></div><div class="rounded-lg border border-slate-200 bg-white p-5 shadow-sm"><p class="text-xs font-black uppercase tracking-wide text-teal-700">{{ plan.price===0?'Activation':'Payment summary' }}</p><dl v-if="plan.price>0" class="mt-4 divide-y divide-slate-100"><Row label="Plan price" :value="money(plan.price)" /><Row label="Wallet balance" :value="money(balance)" /><Row label="Balance after purchase" :value="money(balance-plan.price)" strong /></dl><button v-if="plan.price===0||balance>=plan.price" type="button" class="mt-5 w-full rounded-lg bg-teal-700 px-5 py-3 text-sm font-black text-white hover:bg-teal-800" @click="purchase">{{ plan.price===0?'Activate free plan':'Confirm purchase' }}</button><div v-else class="mt-5 rounded-lg border border-red-100 bg-red-50 p-4"><p class="text-sm font-bold text-red-700">Insufficient wallet balance.</p><Link :href="actions.wallet" class="mt-2 inline-flex text-sm font-black text-red-700">Add funds</Link></div></div></section></DealerLayout></template>
<script setup lang="ts">import{defineComponent,h}from'vue';import{Head,Link,router}from'@inertiajs/vue3';import DealerLayout from '@/Layouts/DealerLayout.vue';const props=defineProps<{plan:any;balance:number;actions:{index:string;purchase:string;wallet:string}}>();const money=(v:number)=>`Rs ${new Intl.NumberFormat('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2}).format(v||0)}`;const purchase=()=>router.post(props.actions.purchase);const Row=defineComponent({props:{label:{type:String,required:true},value:{type:String,required:true},strong:{type:Boolean,default:false}},setup(p){return()=>h('div',{class:'flex justify-between gap-4 py-3'},[h('dt',{class:p.strong?'font-black text-slate-950':'text-sm font-bold text-slate-500'},p.label),h('dd',{class:p.strong?'font-black text-teal-700':'text-sm font-black text-slate-950'},p.value)]);}});</script>
